444444)/sqrt(0.444444444444444*r1^2 + (0.666666666666667*r2 + 1)^2 + 0.444444444444444*(1.0*r3 + 1.0)^2) - 4.5*(0.4 - sqrt(0.444444444444444*(1.0*r1 - 1.0)^2 + (0.666666666666667*r2 - 1)^2 + 0.444444444444444*(1.0*r3 + 1.0)^2))*(0.444444444444444*r3 + 0.444444444444444)/sqrt(0.444444444444444*(1.0*r1 - 1.0)^2 + (0.666666666666667*r2 - 1)^2 + 0.444444444444444*(1.0*r3 + 1.0)^2) - 4.5*(0.4 - sqrt(0.444444444444444*(1.0*r1 + 1.0)^2 + (0.666666666666667*r2 - 1)^2 + 0.444444444444444*(1.0*r3 + 1.0)^2))*(0.444444444444444*r3 + 0.444444444444444)/sqrt(0.444444444444444*(1.0*r1 + 1.0)^2 + (0.666666666666667*r2 - 1)^2 + 0.444444444444444*(1.0*r3 + 1.0)^2) - 2*(0.6 - sqrt(1.0*r1^2 + (1.0*r2 - 0.5)^2 + (1.0*r3 + 1.0)^2))*(r3 + 1.0)/sqrt(1.0*r1^2 + (1.0*r2 - 0.5)^2 + (1.0*r3 + 1.0)^2) - 2*(0.6 - sqrt((1.0*r1 - 1.0)^2 + (1.0*r2 + 0.5)^2 + (1.0*r3 + 1.0)^2))*(r3 + 1.0)/sqrt((1.0*r1 - 1.0)^2 + (1.0*r2 + 0.5)^2 + (1.0*r3 + 1.0)^2) - 2*(0.6 - sqrt((1.0*r1 + 1.0)^2 + (1.0*r2 + 0.5)^2 + (1.0*r3 + 1.0)^2))*(r3 + 1.0)/sqrt((1.0*r1 + 1.0)^2 + (1.0*r2 + 0.5)^2 + (1.0*r3 + 1.0)^2) + 2.0
