    # ∂f_∂s: Evaluate nondilated nonlinear dynamics
    ∂f_∂s = dynamics_nonlinear_ctcs(t_ref,x_ref,vcat(u_ref,1),params)

    # Package partials as linearized matrices
    A = s_ref*∂f_∂x
    B = Matrix([s_ref*∂f_∂u ∂f_∂s])
    Σ = []
    z = -(s_ref*∂f_∂x*x_ref + s_ref*∂f_∂u*u_ref)

    return(A,B,Σ,z)
end

function generate_dynamics_partials_ctcs(params::Quad3DoFCageParams)
    # Symbols for differentiable quantities
    r1,r2,r3 = symbols("r1 r2 r3", real=true)
    v1,v2,v3 = symbols("v1 v2 v3", real=true)
    T1,T2,T3 = symbols("T1 T2 T3", real=true)
    intT     = symbols("intT"; real=true)
    intxi    = symbols("intxi", real=true)

    # Symbol canonicalization
    x = [r1;r2;r3;v1;v2;v3;intT;intxi]
    u = [T1;T2;T3]
    nx,nu = length(x),length(u) 

    # Evaluate 3-DOF dynamics
    A,B,p = dynamics_linear(params)
    f_3DoF = A*x[1:6] + B*u + p

    # Evaluate extra terms
    Tnorm  = norm(u) # thrust integral
    xi,_,_ = path_constraint_eval(x,u,params) # CTCS violation

    # Concatenate
    f = [f_3DoF;Tnorm;xi]

    # Print out all partial elements
    for i = 1:nx
        for j = 1:nx
            ∂fi_∂xj = diff(f[i],x[j])
            print("∂f_∂x[$(i),$(j)] = $(string(∂fi_∂xj))\n")
        end
        for j = 1:nu
            ∂fi_∂uj = diff(f[i],u[j])
            print("∂f_∂u[$(i),$(j)] = $(string(∂fi_∂uj))\n")
        end
    end
end